pub const fn is_reapable(self) -> bool {
    matches!(self, Self::OrphanedDead)
}

/// True when no check hard-failed — the run may proceed (warnings and all).
    #[must_use]
    pub const fn passed(&self) -> bool {
        self.failures.is_empty()
    }

// A code-class verdict must be present for the result to pass: absence of the
// deterministic floor escalates (never passes), and no judgment verdict can
// substitute for it.

func (g Grant) CyclesWithin(n int) bool {
	return g.MaxCycles == 0 || n <= g.MaxCycles
}

